import{_ as a,o as r,c as e,av as o}from"./chunks/framework.BDRJ0RPA.js";const p=JSON.parse('{"title":"介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1775314822000}'),d={name:"guide/introduction.md"};function n(i,t,l,s,h,u){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="介绍" tabindex="-1">介绍 <a class="header-anchor" href="#介绍" aria-label="Permalink to &quot;介绍&quot;">​</a></h1><p>Haura UI 是一个克制而精致的 Vue 3 组件库。</p><h2 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h2><p><strong>克制而精致，耐看而不乏味</strong></p><p>Haura UI 追求的是一种克制的精致感。我们不堆砌特效，而是通过微妙的光效和节奏感的动效，让界面在细节处展现品质。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><table tabindex="0"><thead><tr><th>特性</th><th>说明</th></tr></thead><tbody><tr><td><strong>微妙光效系统</strong></td><td>聚焦、悬停、选中时的柔和光晕</td></tr><tr><td><strong>动效节奏感</strong></td><td>独特的缓动曲线和时序编排</td></tr><tr><td><strong>完整 Props</strong></td><td>对标主流 UI 库的属性配置</td></tr><tr><td><strong>6 套主题</strong></td><td>亮色/暗色 × 中性/暖色/冷色</td></tr><tr><td><strong>TypeScript</strong></td><td>完整的类型定义</td></tr><tr><td><strong>国际化</strong></td><td>内置多语言支持</td></tr></tbody></table><h2 id="品牌寓意" tabindex="-1">品牌寓意 <a class="header-anchor" href="#品牌寓意" aria-label="Permalink to &quot;品牌寓意&quot;">​</a></h2><p><strong>H + Aura = 你的光环</strong></p><p>Haura（光环）代表每个开发者都能在项目中展现自己的光芒。我们提供克制而精致的基础，让开发者能够专注于创造独特的体验。</p><h2 id="技术栈" tabindex="-1">技术栈 <a class="header-anchor" href="#技术栈" aria-label="Permalink to &quot;技术栈&quot;">​</a></h2><ul><li><strong>Vue 3.3+</strong> — Composition API</li><li><strong>TypeScript 5.0+</strong> — 完整类型支持</li><li><strong>UnoCSS</strong> — 原子化 CSS</li><li><strong>VitePress</strong> — 文档站点</li></ul><h2 id="版本" tabindex="-1">版本 <a class="header-anchor" href="#版本" aria-label="Permalink to &quot;版本&quot;">​</a></h2><p>目前处于 Beta 阶段，API 可能会有变动。</p><table tabindex="0"><thead><tr><th>版本</th><th>状态</th></tr></thead><tbody><tr><td>0.x</td><td>Beta</td></tr></tbody></table><h2 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h2><p>欢迎提交 Issue 和 Pull Request！</p><ul><li><a href="https://github.com/yzdalhj/haura" target="_blank" rel="noreferrer">GitHub 仓库</a></li><li><a href="https://github.com/yzdalhj/haura/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">贡献指南</a></li></ul><h2 id="许可证" tabindex="-1">许可证 <a class="header-anchor" href="#许可证" aria-label="Permalink to &quot;许可证&quot;">​</a></h2><p><a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT</a></p>',20)])])}const b=a(d,[["render",n]]);export{p as __pageData,b as default};
